const thread = $input.item.json;
const messages = thread.messages || [];

function decodeBase64(data) {
  if (!data) return '';
  try {
    return Buffer.from(data.replace(/-/g, '+').replace(/_/g, '/'), 'base64').toString('utf-8');
  } catch (e) { return ''; }
}

function extractBody(payload) {
  if (!payload) return '';
  if (payload.body && payload.body.data) return decodeBase64(payload.body.data);
  if (payload.parts) {
    const text = payload.parts.find(p => p.mimeType === 'text/plain');
    if (text && text.body && text.body.data) return decodeBase64(text.body.data);
    const html = payload.parts.find(p => p.mimeType === 'text/html');
    if (html && html.body && html.body.data) return decodeBase64(html.body.data).replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
  }
  return '';
}

function getHeader(headers, name) {
  const h = (headers || []).find(h => h.name.toLowerCase() === name.toLowerCase());
  return h ? h.value : '';
}

if (messages.length === 0) {
  return [{ json: { stacieStartedThread: false } }];
}

// Check if Stacie sent the FIRST message in this thread
const firstMsg = messages[0];
const firstHeaders = firstMsg.payload && firstMsg.payload.headers ? firstMsg.payload.headers : [];
const firstFrom = getHeader(firstHeaders, 'From');
const stacieStartedThread = firstFrom.toLowerCase().includes('info@tribalcowboy.com');

// Only a single message = Stacie hasn't replied yet or this isn't a thread
if (messages.length < 2 || !stacieStartedThread) {
  return [{ json: { stacieStartedThread: false } }];
}

// Parse all messages for full thread history
const parsedMessages = messages.map((msg, i) => {
  const headers = msg.payload && msg.payload.headers ? msg.payload.headers : [];
  const from = getHeader(headers, 'From');
  const date = getHeader(headers, 'Date');
  const body = extractBody(msg.payload).substring(0, 800);
  const direction = from.toLowerCase().includes('info@tribalcowboy.com') ? 'SENT BY STACIE' : 'RECEIVED FROM THEM';
  return `[${direction} — ${date}]\nFrom: ${from}\n\n${body}`;
});

// Latest message (the one that just arrived)
const latestMsg = messages[messages.length - 1];
const latestHeaders = latestMsg.payload && latestMsg.payload.headers ? latestMsg.payload.headers : [];

return [{
  json: {
    stacieStartedThread: true,
    threadHistory: parsedMessages.join('\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n'),
    messageCount: messages.length,
    latestSender: getHeader(latestHeaders, 'From'),
    latestSubject: getHeader(latestHeaders, 'Subject'),
    latestBody: extractBody(latestMsg.payload).substring(0, 1000),
    latestDate: getHeader(latestHeaders, 'Date'),
    threadId: thread.id
  }
}];

